insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'name-recognition', '11111111-1111-1111-1111-111111111111', 'Name / Look at Me', 'obedience', 'locked', ARRAY[]::text[], 1,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Lure eye contact","successCriteria":"Turns head toward handler on name/lure 8 of 10 reps in a quiet room (beginner)","sessionsRequired":2,"completedSessions":0},{"title":"Distance and unexpected timing","successCriteria":"Orients from across the room, mid-walk, or mid-play (medium)","sessionsRequired":3,"completedSessions":0},{"title":"Different people, places, distractions","successCriteria":"Responds to name for different people in different places 8 of 10 reps (hard)","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"Look at Me — reference video","type":"video","url":"https://www.youtube.com/watch?v=FG9xSgN86BM","publisher":"Dog Rules reference"},{"title":"Give me your attention you booger","type":"article","url":"https://kaufmannspuppytraining.com/en/get-dogs-attention/","publisher":"Kaufmann''s Puppy Training"},{"title":"How to Teach Your Dog Their Name","type":"article","url":"https://www.akc.org/expert-advice/training/how-to-teach-dog-name/","publisher":"AKC"}]'::jsonb, 'Week 1 command per the real training schedule. Reliable orientation to the puppy''s name is the first building block every later cue depends on, since a dog can''t respond to instruction it isn''t already listening for.'
)
