insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'food-lure', '11111111-1111-1111-1111-111111111111', 'Food lure mechanics', 'obedience', 'locked', ARRAY[]::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Nose-follows-hand","successCriteria":"Tracks a treat in a closed fist through a simple path 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Lure into basic position shifts","successCriteria":"Follows lure into a sit or a turn without freezing or jumping","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"Lure-and-reward training plan","type":"plan","url":"https://www.akc.org/expert-advice/training/lure-reward-training/","publisher":"AKC"},{"title":"Lure training fundamentals","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+lure+training+fundamentals+puppy","publisher":"Kikopup"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Clean lure mechanics (steady hand, correct pace, timely release) are the mechanical skill behind sit, down, touch, shake, spin, and roll over, so it is worth teaching as its own milestone before those cues stack on top of it.'
)
