insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'focus', '11111111-1111-1111-1111-111111111111', 'Focus / engagement', 'obedience', 'locked', ARRAY['name-recognition']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Eye contact for a treat","successCriteria":"Offers voluntary eye contact 8 of 10 reps indoors","sessionsRequired":2,"completedSessions":0},{"title":"Hold eye contact briefly","successCriteria":"Holds eye contact 3 seconds before reward","sessionsRequired":3,"completedSessions":0},{"title":"Focus around mild distraction","successCriteria":"Re-engages with handler within 2 seconds of a mild distraction outdoors","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"Grab & Hold Your Dog''s Attention With the \"Watch Me\" Command","type":"article","url":"https://www.akc.org/expert-advice/training/watch-me-command-grab-dogs-attention/","publisher":"AKC"},{"title":"How to Train Your Dog to Stay Focused Around Distractions","type":"article","url":"https://www.akc.org/expert-advice/training/training-dogs-to-ignore-distractions/","publisher":"AKC"},{"title":"Engagement and focus training","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+engagement+focus+training+puppy","publisher":"Kikopup"}]'::jsonb, 'Builds on name recognition by teaching sustained voluntary attention, which down, stay, spin, heel, and impulse control all rely on to hold the dog''s attention through a full behavior.'
)
