insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'impulse-control', '11111111-1111-1111-1111-111111111111', 'Impulse control', 'obedience', 'locked', ARRAY['focus']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"It''s Yer Choice / bowl game","successCriteria":"Waits without lunging while food bowl lowers 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Wait at doorway / crate","successCriteria":"Holds position while door opens until released","sessionsRequired":3,"completedSessions":0},{"title":"Settle during play arousal","successCriteria":"Interrupts play and offers a sit within 3 seconds of cue","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"It''s Your Choice — impulse training","type":"video","url":"https://www.youtube.com/watch?v=QIuxm5r17nE","publisher":"Dog Rules reference"},{"title":"13 Training Games","type":"article","url":"https://journeydogtraining.com/13-dog-training-games/","publisher":"Journey Dog Training"},{"title":"Impulse Control for Dogs: Dog Self-Control Training","type":"article","url":"https://www.akc.org/expert-advice/training/teaching-your-dog-self-control/","publisher":"AKC"}]'::jsonb, 'Also listed as its own item in the 8-16 week training schedule. Extends focus into self-restraint around real motivators (food, doors, arousal), and is the readiness gate leave-it and wait depend on before they can be proofed in daily life.'
)
