insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'drop-it', '11111111-1111-1111-1111-111111111111', 'Drop it', 'obedience', 'locked', ARRAY['marker-word', 'food-lure']::text[], NULL,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Trade for low-value toy","successCriteria":"Releases a low-value toy for a treat trade 8 of 10 reps","sessionsRequired":2,"completedSessions":0},{"title":"Add verbal cue","successCriteria":"Drops item on verbal cue before treat is shown 8 of 10 reps","sessionsRequired":3,"completedSessions":0},{"title":"Proof with higher-value items","successCriteria":"Drops a favorite toy or found object on first cue without chase","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"How to Teach Your Dog to Drop It","type":"article","url":"https://www.akc.org/expert-advice/training/teaching-your-dog-to-drop-it/","publisher":"AKC"},{"title":"Drop it without a chase","type":"video","url":"https://www.youtube.com/results?search_query=kikopup+drop+it+trade+training","publisher":"Kikopup"},{"title":"Positive reinforcement training basics","type":"article","url":"https://www.humanesociety.org/resources/positive-reinforcement-training","publisher":"Humane Society"}]'::jsonb, 'Teaches a fair trade instead of a grab, which prevents resource guarding and is required before leave-it (impulse control around items already in the mouth) and retrieve (releasing the toy into the handler''s hand).'
)
