  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Catch and reward 3 seconds","successCriteria":"Holds sit-stay 3 seconds with handler at arm''s length 8 of 10 reps (beginner)","sessionsRequired":3,"completedSessions":0},{"title":"Increase distance and duration","successCriteria":"Holds stay 15 seconds with handler 6 feet away, controlled environment (medium)","sessionsRequired":4,"completedSessions":0},{"title":"Surprise stay, uncontrolled environment","successCriteria":"Holds stay through a squeaky toy rolling by, other toys, or people (hard)","sessionsRequired":4,"completedSessions":0}]'::jsonb, '[{"title":"Stay — 1:45 min mark","type":"video","url":"https://www.youtube.com/watch?v=GAziMECDxD0&t=313s","publisher":"Dog Rules reference"},{"title":"Stay with distraction — 2 min and 4:45 min marks","type":"video","url":"https://www.youtube.com/watch?v=2-_rxxKxseU","publisher":"Dog Rules reference"},{"title":"How to Teach Your Dog to Stay","type":"article","url":"https://www.akc.org/expert-advice/training/teach-your-dog-to-stay/","publisher":"AKC"}]'::jsonb, 'Week 4 command per the real training schedule. Layers duration on top of a reliable sit and the focus needed to hold it, and becomes the foundation for place and advanced recall.'
)
