  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Settle on the mat","successCriteria":"Reaches a relaxed one-hip position on the mat and gets kibble; if the dog leaves the mat, pick it up and restart from the last spot","sessionsRequired":3,"completedSessions":0},{"title":"Send from a short distance","successCriteria":"Runs to mat and settles from 6 feet away on cue","sessionsRequired":4,"completedSessions":0},{"title":"Hold place through household activity","successCriteria":"Stays on mat through doorbell or meal prep until released","sessionsRequired":5,"completedSessions":0}]'::jsonb, '[{"title":"Dr. Karen Overall Protocol for Relaxation (PDF)","type":"plan","url":"https://journeydogtraining.com/wp-content/uploads/2017/07/ProtocolforRelaxation.pdf","publisher":"Journey Dog Training"},{"title":"Protocol Day 0 / Day 1 / Day 2 / Day 3","type":"video","url":"https://www.youtube.com/watch?v=wJGHOhbmjac&t=259s","publisher":"Dog Rules reference"},{"title":"How To Teach Your Dog To Go to Their Place","type":"article","url":"https://www.akc.org/expert-advice/training/teaching-go-to-your-place/","publisher":"AKC"}]'::jsonb, 'Week 6-8 command per the real training schedule, and officially the start of the formal training program per Dog.xlsx. Combines a settled down with stay-level duration on a specific target.'
