insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'crate-training', '11111111-1111-1111-1111-111111111111', 'Crate training', 'handling', 'locked', ARRAY[]::text[], 1,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Positive introduction","successCriteria":"Sniffs and explores the open crate with treats/toys inside, no door closing yet","sessionsRequired":3,"completedSessions":0},{"title":"Close the door briefly","successCriteria":"Accepts the door slowly closed (not locked) while treats feed through, 15 min or less","sessionsRequired":4,"completedSessions":0},{"title":"Build duration","successCriteria":"Settles calmly in crate for 15 min - 1 hr after exercise, low frequency of longer stretches","sessionsRequired":5,"completedSessions":0}]'::jsonb, '[{"title":"Crate Training (Zak George)","type":"video","url":"https://www.youtube.com/watch?v=hesi8WxLWVE","publisher":"Dog Rules reference"},{"title":"Crate training — other resource, 10:00 mark","type":"video","url":"https://www.youtube.com/watch?v=R0vTyXCP5vY","publisher":"Zak George"},{"title":"Puppy Potty Training Tips (crate section)","type":"article","url":"https://www.akc.org/expert-advice/training/potty-training-puppy-tips/","publisher":"AKC"}]'::jsonb, 'Major rule: the crate is never a punishment. Always exercise first, keep early sessions between 15 minutes and 1 hour, and it''s fine to run more frequent short stretches while building up duration. This is the direct foundation for every alone-time milestone in Section 4 of the household knowledge base.'
)
