insert into milestones (id, household_id, title, track, status, dependencies, age_gate_weeks, dog_ids, steps, sources, why) values (
  'settle-alone-time', '11111111-1111-1111-1111-111111111111', 'Settle / home alone', 'confidence', 'locked', ARRAY['crate-training']::text[], 8,
  ARRAY['11111111-1111-1111-1111-111111111114']::uuid[], '[{"title":"Short departures","successCriteria":"Settles calmly for 15-30 min departures with no crying at the door","sessionsRequired":4,"completedSessions":0},{"title":"1-2 hour stretch","successCriteria":"Handles a 1-2 hour departure (e.g. a gym class) calmly, logged in the alone-time tracker","sessionsRequired":3,"completedSessions":0},{"title":"3-4 hour stretch","successCriteria":"Handles a 3-4 hour departure calmly ahead of the BYU/Notre Dame tailgate (10/17) target","sessionsRequired":3,"completedSessions":0}]'::jsonb, '[{"title":"Puppy Training Timeline (alone-time conditioning)","type":"article","url":"https://www.akc.org/expert-advice/training/puppy-training-timeline-teaching-good-behavior-before-its-too-late/","publisher":"AKC"},{"title":"Dr. Karen Overall Protocol for Relaxation (PDF)","type":"plan","url":"https://journeydogtraining.com/wp-content/uploads/2017/07/ProtocolforRelaxation.pdf","publisher":"Journey Dog Training"}]'::jsonb, 'Listed as ''Settle (separation anxiety)'' in the 8-16 week training schedule, and directly tied to the household''s real calendar: several hours alone for September concerts, ~4 hours for the 10/17 BYU/Notre Dame tailgate, a full evening for Mammoth hockey, and a full day (6-8 hrs) for late-December ski trips. Log real achieved durations in the alone-time tracker so the app can flag gaps against upcoming commitments before they happen.'
)
